&LogGUID = GUID.NewGuid()

//verifica id da sessao.
verificaidsessao.Call(&DevRandon, &IsAcessoConcedido, &IsAtualizaTudo, &wwpContext)

//GravaLogDevNew(&wwpContext.EmpCod,&LogGUID,&Pgmname,'&sdtProduto',&sdtProduto.ToJson())

if &IsAcessoConcedido = true //Acesso concedido

	RetornaConfSistema_CadastroProduto.Call(&wwpContext.EmpCod, &wwpContext.FilCod, &sdtConfSistema_CadastroProduto)

	Do Case
		CAse &OqueFazer = 'UPD' //update

//			GravaLogDevNew(&wwpContext.EmpCod,&LogGUID,&Pgmname,'&OqueFazer',&OqueFazer)

			&ProCod = &sdtProduto.Cod
			prcLoadProduto.call(&wwpContext.EmpCod, &ProCod, &sdtGraVaProduto)

			if &sdtGraVaProduto.ProNcmCest.IsEmpty()
				&sdtGraVaProduto.ProNcmCest = 9999999
			Endif			
			do 'gravar'

		Case &OqueFazer = 'INS' //insert		
			do 'gravar'

	EndCAse
Else

	//mensagem erro
Endif


//GRAVAR	
sub 'gravar'
	&sdtRetornowbs.Sts = 'E995'

	Do CAse
		CAse &sdtProduto.Nom.IsEmpty()
			&sdtRetornowbs.Obs = 'Descrição do produto não informada!'
			return
		CAse  &sdtProduto.TDef.IsEmpty()
			&sdtRetornowbs.Obs = 'Definição do produto não informada!'
			return
		CAse  &sdtProduto.Gcod.IsEmpty()
			&sdtRetornowbs.Obs = 'Grupo produtos não informado!'
			return
		CAse  &sdtProduto.Ccod.IsEmpty()
			&sdtRetornowbs.Obs = 'Categoria imposto não informada!'
			return
		Otherwise
			//	If (&ProStsRag = Status_SimNao.Sim) AND &ProCodSia.IsEmpty()
			//		&sdtRetornowbs.Obs = 'Produto exige Cód.Siagro, e não foi informado!'
			//		return
			//	EndIf

			For Each ORder EmpCod
				Where EmpCod = &wwpContext.EmpCod

				&IsErroMarca = true //MARCA
				For Each Order EmpCod, MarCod
					Where MarCod = &sdtProduto.MarC
					&IsErroMarca = false
					Exit
				EndFor

				&IsErroSetor = true
				For Each Order EmpCod, SetCod
					Where SetCod = &sdtProduto.Scod //SETOR
					&IsErroSetor = false
					Exit
				EndFor

				&IsErroEmbalagem = true
				For Each Order EmpCod, EmbCod //EMBALAGEM
					Where EmbCod = &sdtProduto.Ecod
					&IsErroEmbalagem = false
					Exit
				EndFor

				&IsErroGrupo = true
				For Each Order EmpCod, GrupCod //GRUPO
					Where GrupCod = &sdtProduto.Gcod
					Where GrupAnaSin = 'A' //ANALITICO
					&IsErroGrupo = false
					Exit
				EndFor

				&CatSts = Status_AtivoInativo.INATIVO
				For Each ORder EmpCod, CatCod //CATEGORIA
					Where CatCod = &sdtProduto.Ccod
					&CatSts = CatSts
					Exit
				EndFor


				//	&isErroClassificacao = true
				//	For Each Order EmpCod, ClsPrdCod
				//		Where ClsPrdCod = &ClsPrdCod
				//		&ProClsPrdCod = ClsPrdCod
				//		&isErroClassificacao = false
				//		Exit
				//	When none
				//		if &ProClsPrdCodNom.IsEmpty()
				//			&isErroClassificacao = false
				//		Endif
				//	EndFor

				//	&IsErroProcesso = true
				//	&PrcProCod= 0
				//	For Each Order EmpCod, PrcProCod
				//		Where EmpCod = &wwpContext.EmpCod
				//		Where PrcProNom = &PrcProNom
				//		&PrcProCod = PrcProCod		
				//		&IsErroProcesso = false
				//		Exit
				//	When none
				//		if &PrcProNom.IsEmpty()
				//			&IsErroProcesso = false
				//		Endif
				//	EndFor
			EndFor

			ValidaNcm.Call(&sdtProduto.Ncm, &NcmDes, &IsErroNCM)			
			if &IsErroNCM = false and (&sdtProduto.Cest <> 9999999 and &sdtProduto.Cest <> 0)
				For Each Order NcmCod, NcmCestCod
					Where NcmCod = &sdtProduto.Ncm
					Where NcmCestCod = &sdtProduto.Cest
					Exit
				When none
					&sdtRetornowbs.obs = 'CEST INVÁLIDO PARA O NCM INFORMADO!'			
				EndFor
			Endif

			&IsDisponivel = true //CASO INFORMOU CODIGO VALIDA
			if &OqueFazer = 'INS' and not &sdtProduto.Cod.IsEmpty() 
				verificaCodigoDisponivelProduto.Call(&wwpContext.EmpCod, &sdtProduto.Cod, &IsDisponivel) 
			Endif

			&RepetidoReferenciaMensagem.SetEmpty()	
			if not &sdtProduto.Ref.IsEmpty() //## Referencia Repetido
				ValidaCodigoReferenciaRepetido.Call(&wwpContext.EmpCod, &sdtProduto.Cod,  1, &sdtProduto.Ref, &RepetidoReferenciaMensagem) 
			EndIF

			&RepetidoEanMensagem.SetEmpty()
			if not &sdtProduto.Bar.IsEmpty() //## EAN 13
				ValidaCodigoReferenciaRepetido.Call(&wwpContext.EmpCod,&sdtProduto.Cod, 1, &sdtProduto.Bar, &RepetidoEanMensagem) 
			EndIF

			Do CAse
				Case &CatSts = Status_AtivoInativo.INATIVO
					&sdtRetornowbs.Obs = 'Categoria Produto Não informada ou inativa!'
					return

					////		CAse &ProObrAnp = Status_SimNao.Sim and &ProCodAnp.IsEmpty()
					////			&Mensagem = 'Obrigatório informar ANP e código ANP não informado.'
					////			do 'msgErro'
					////			
					////		CAse &ProMedObr = Status_SimNao.Sim and &ProMedAnv.IsEmpty()
					////			&Mensagem = 'Obrigatório informar código ANVISA.'
					////			do 'msgErro'
					////			
					////		CAse &ProMedObr = Status_SimNao.Sim and &ProMedVlrMax = 0
					////			&Mensagem = 'Obrigatório informar valor máximo do consumidor.'
					////			do 'msgErro'
					////			
					////		Case (&ProObrAnp = Status_SimNao.Sim) AND &ProDscAnp.IsEmpty()
					////			&Mensagem = 'Obrigatório informar ANP e descrição produto ANP não informado.'
					////			do 'msgErro'
					////			
					////		CAse &isErroClassificacao = true
					////			&Mensagem = 'Código de classificação produção não cadastrado!'
					////			do 'msgErro'

				Case &sdtProduto.TCus.IsEmpty()
					&sdtRetornowbs.Obs = 'Tipo de custo é obrigatório.'
					return

				CAse &IsDisponivel = false 
					&sdtRetornowbs.Obs = 'Código já utilizado, informe outro código para o cadastro.'
					return

				Case &IsErroEmbalagem = true
					&sdtRetornowbs.Obs = 'Embalagem não informada ou inválida!'
					return

				Case &IsErroMarca = true
					&sdtRetornowbs.Obs = 'Marca não informada ou inválida!'
					return

					////		Case &IsErroProcesso = true
					////			&Mensagem = 'Código do processo produtivo não Cadastrado!'
					////			do 'msgErro'
					////			&PrcProCod.SetFocus()

				Case &IsErroSetor = true
					&sdtRetornowbs.Obs = 'Setor não informado ou inválido!'
					return

				Case &IsErroNCM = true and &sdtProduto.Ncm <> 0 and &sdtProduto.Ncm <> 99
					&sdtRetornowbs.Obs = 'Código de NCM não Cadastrado ou fora da Vigência!'
					return

				Case &IsErroGrupo = true
					&sdtRetornowbs.Obs = 'Grupo de produtos inválido ou não informado!'
					Return

				Case not &sdtProduto.TDef in (Definicao.FABRICADO, Definicao.SUBPRODUTO, Definicao.SEMIACABADO) and (&sdtProduto.TCus = TipoCusto.Receita)
					&sdtRetornowbs.Obs = 'Tipo de Custo Receita, Permitido somente para Produtos Definidos como Fabricação Própria ou Sub-Produto ou Semi-Acabado!'
					return

				CAse (not &RepetidoReferenciaMensagem.IsEmpty()) and (not &sdtProduto.Ref.IsEmpty())
					&sdtRetornowbs.Obs = &RepetidoReferenciaMensagem
					return

				Case (not &RepetidoEanMensagem.IsEmpty()) and (not &sdtProduto.Bar.IsEmpty())
					&sdtRetornowbs.Obs = &RepetidoEanMensagem
					return

				Otherwise
					//GravaLogDevNew(&wwpContext.EmpCod,&LogGUID,&Pgmname,'Otherwise','Otherwise')

					&sdtGravaProduto.ProCod = &sdtProduto.Cod
					&sdtGravaProduto.ProRef = &sdtProduto.Ref.ToUpper()
					&sdtGravaProduto.ProBar = &sdtProduto.Bar
					&sdtGravaProduto.ProNom = &sdtProduto.Nom.ToUpper()
					&sdtGravaProduto.Prosts.FromString(&sdtProduto.Psts)
					&sdtGravaProduto.ProEmbCod = &sdtProduto.Ecod
					&sdtGravaProduto.MarCod = &sdtProduto.MarC
					&sdtGravaProduto.ProSetCod = &sdtProduto.Scod
					&sdtGravaProduto.GrupCod = &sdtProduto.GCod
					&sdtGravaProduto.ProTipDef.FromString(&sdtProduto.TDef)

					&sdtGravaProduto.ProNcmCod = &sdtProduto.Ncm
					&sdtGravaProduto.ProNcmCest = &sdtProduto.Cest
					if &sdtProduto.Cest = 9999999
						&sdtGravaProduto.ProNcmCest = 0
					EndIf

					&sdtGravaProduto.ProCatCod = &sdtProduto.Ccod
					//////&sdtGraVaProduto.TabPrc1 = &TabPrc1 //ESSE NAO PRECISA JDF
					////&sdtGravaProduto.ProPadForCod = &ProPadForCod
					&sdtGravaProduto.ProTipCus = &sdtProduto.TCus
					////&sdtGravaProduto.ProPadUltCmp = &ProPadUltCmp

					&ProVlrCusFix.FromString(&sdtProduto.VCusFix)
					&sdtGravaProduto.ProVlrCusFix = &ProVlrCusFix
					&sdtGravaProduto.ProVlrCus = &ProVlrCusFix

					////&sdtGravaProduto.ProIMCTot = &ProIMCTot
					////&sdtGravaProduto.ProIMC = &ProIMC
					////&sdtGravaProduto.ProDet = &ProDet
					////&sdtGravaProduto.ProPesLiq = &ProPesLiq
					////&sdtGravaProduto.ProDesMax = &ProDesMax
					////&sdtGravaProduto.ProQtdEmb = &ProQtdEmb
					////&sdtGravaProduto.ProInfCmp = &ProInfCmp
					////&sdtGravaProduto.ProReqQtd = &ProReqQtd
					////&sdtGravaProduto.ProRepItm = &ProRepItm
					////&sdtGravaProduto.ProSolLot = &ProSolLot
					////&sdtGravaProduto.ProStsRag = &ProStsRag
					////&sdtGravaProduto.ProCodSia = &ProCodSia 
					////&sdtGravaProduto.ProObrAnp = &ProObrAnp

					Do CAse
						CAse &sdtProduto.Anp = 'A' //Produto ANP
							////&sdtGravaProduto.ProCodAnp = &ProCodAnp
							////&sdtGravaProduto.ProDscAnp = &ProDscAnp
							////&sdtGravaProduto.ProPerGlp = &ProPerGlp
							////&sdtGravaProduto.ProPerGni = &ProPerGni
							////&sdtGravaProduto.ProPerGnn = &ProPerGnn
							////&sdtGravaProduto.ProVlrPar = &ProVlrPar				
						CAse &sdtProduto.Anp = 'R' //RECEITUARIO

					EndCase


					////&sdtGravaProduto.ProQtdCmpEmb = &ProQtdCmpEmb
					////
					//////medicamentos
					////&sdtGravaProduto.ProMedObr = &ProMedObr 
					////&sdtGravaProduto.ProMedAnv = &ProMedAnv 
					////&sdtGravaProduto.ProMedMot = &ProMedMot 
					////&sdtGravaProduto.ProMedVlrMax = &ProMedVlrMax 
					////
					////&sdtGraVaProduto.proEstTip = &ProEstTip				
					////&sdtGraVaProduto.ProTip = &ProTip
					////
					////&sdtGravaProduto.ProNomNF		= &ProNomNF 
					////&sdtGravaProduto.ProDesEtq1		= &ProDesEtq1 
					////&sdtGravaProduto.ProDesEtq2		= &ProDesEtq2 	
					////&sdtGravaProduto.ProDesEtq3 	= &ProDesEtq3 	
					////&sdtGravaProduto.ProOriCod		= &ProOriCod 	
					&sdtGravaProduto.ProOriTriCod.FromString(&sdtProduto.Pori.Trim())
					&sdtGraVaProduto.ProQTdMin.FromString(&sdtProduto.EstMin)
					&sdtGraVaProduto.ProQtdMax.FromString(&sdtProduto.EstMax)

					////&sdtGraVaProduto.ProMarSeg 		= &ProMarSeg
					if &sdtGravaProduto.ProTipCus = TipoCusto.Receita
						&sdtGraVaProduto.ProTipCusAcrRec = false
					Else
						////&sdtGraVaProduto.ProTipCusAcrRec = &ProTipCusAcrRec
					Endif

					////
					////&sdtGraVaProduto.ProDesEtq 	= &ProDesEtq
					////&sdtGraVaProduto.ProCorCod 	= &ProCorCod
					////&sdtGraVaProduto.ProDetNfe 	= &ProDetNfe
					////&sdtGraVaProduto.ProQtdVol 	= &ProQtdVol
					////&sdtGraVaProduto.ProTam 	= &ProTam
					////&sdtGraVaProduto.ProReqVlr 	= &ProReqVlr
					////&sdtGraVaProduto.ProReqVen 	= &ProReqVen
					////&sdtGraVaProduto.ProVendMeio = &ProVendMeio
					////
					////&sdtGravaProduto.ProIsSojaFethab	= &ProIsSojaFethab 	
					////&sdtGravaProduto.ProIncSojaFethab   = &ProIncSojaFethab
					////&sdtGravaProduto.ProIsIagro			= &ProIsIagro
					////&sdtGravaProduto.ProIncIagro		= &ProIncIagro
					////&sdtGravaProduto.ProIsGadoFethab	= &ProIsGadoFethab 	
					////&sdtGravaProduto.ProIncGadoFethab   = &ProIncGadoFethab
					////&sdtGravaProduto.ProIsFabov			= &ProIsFabov
					////&sdtGravaProduto.ProIncFabov		= &ProIncFabov
					////&sdtGraVaProduto.ProDedIcms 		= &ProDedIcms
					////&sdtGraVaProduto.ProDedIpi 			= &ProDedIpi 
					////
					////&sdtGraVaProduto.ProEtqUndRef = &ProEtqUndRef 
					////&sdtGraVaProduto.ProEtqUndQtd = &ProEtqUndQtd 
					////&sdtGraVaProduto.ProEtqEmbRef = &ProEtqEmbRef 
					////&sdtGraVaProduto.ProEtqEmbQtd = &ProEtqEmbQtd 
					////
					////&sdtGravaProduto.ProClsPrdCod = &ProClsPrdCod
					////
					//////ICMS RETIDO
					////&sdtGravaProduto.ProBasIcmsRet = &ProBasIcmsRet
					////&sdtGravaProduto.ProTaxIcmsRet = &ProTaxIcmsRet
					////&sdtGravaProduto.ProVlrIcmsRet = &ProVlrIcmsRet
					////&sdtGravaProduto.ProBarTrib = &ProBarTrib
					////&sdtGraVaProduto.ProUndTrib = &ProUndTrib
					////&SdtGravaProduto.PrcProCod = &PrcProCod 
					////
					////&sdtGravaProduto.ProCmbUfOri = &ProCmbUfOri 
					////&sdtGravaProduto.ProCmbPerOri = &ProCmbPerOri 
					////
					&sdtGraVaProduto.wwpContextUserName = &wwpContext.UserName
					////&sdtGravaProduto.ProCnaeCod = &ProCnaeCod


					//GRAVA DADOS DO PRODUTO
					&Mode = iif(&OqueFazer = 'INS', TrnMode.Insert, TrnMode.Update)
					prcGravaProduto.Call(&Mode, &wwpContext.EmpCod, &wwpContext.FilCod, &wwpContext.PesCod, &wwpContext.UserName, &sdtGraVaProduto, &outProCod, &outProRef)
					&ProCod = &outProCod

					////if not &tmpNFeCod.IsEmpty() //ATUALIZA TEMPORARIA NOTAS
					////	FornecedorProduto_AtualizaCodBarras.Call(&tmpNFeCod, &wwpContext.EmpCod, &ForCNPJ, &tmpProForCod, &tmpNfeProBar, &ParProRef, '','', 0, 0, 0)
					////Endif

					If &sdtConfSistema_CadastroProduto.TCon130_MostrarTabelaPreco <> 'N' //ATUALIZA PRECO

						For &ProdutosPreco in &sdtProduto.precos
							RetornaConfiguracoesTabelaVenda.Call(&wwpContext.EmpCod, &ProdutosPreco.tabC, &TabALtCod, &TabNom, &TabRecCol, &TabIsPerCol1)
							RetornaPrecoVendaProduto.Call(&wwpContext.EmpCod, &ProdutosPreco.tabC, &ProCod, &TabPrc1, &TabPrc2, &TabPrc3, &TabPrc4, &TabPrc5, &TabPrc6, &TabPrc7, &TabPrc8, &TabPrc9, &Perc1, &Perc2, &Perc3, &Perc4, &Perc5, &Perc6, &Perc7, &Perc8, &Perc9)
							&OldTabPrc1 = &TabPrc1
							&OldTabPrc2 = &TabPrc2
							&OldTabPrc3  = &TabPrc3
							&OldTabPrc4  = &TabPrc4
							&OldTabPrc5  = &TabPrc5
							&OldTabPrc6  = &TabPrc6
							&OldTabPrc7  = &TabPrc7
							&OldTabPrc8  = &TabPrc8
							&OldTabPrc9  = &TabPrc9

							&TabPrc1.FromString(&ProdutosPreco.v1)
							&TabPrc2.FromString(&ProdutosPreco.v2)
							&TAbPrc3.FromString(&ProdutosPreco.v3)
							&TAbPrc4.FromString(&ProdutosPreco.v4)
							&TAbPrc5.FromString(&ProdutosPreco.v5)
							&TAbPrc6.FromString(&ProdutosPreco.v6)
							&TAbPrc7.FromString(&ProdutosPreco.v7)
							&TAbPrc8.FromString(&ProdutosPreco.v8)
							&TAbPrc9.FromString(&ProdutosPreco.v9)

							//PERCENTUAL POR HORA NAO ATUALIZA
							//&Perc1, &Perc2,&Perc3,&Perc4,&Perc5,&Perc6,&Perc7,&Perc8,&Perc9

							if (&OldTabPrc1 <> &TabPrc1 or &OldTabPrc2 <> &TabPrc2 or &OldTabPrc3 <> &TAbPrc3 or &OldTabPrc4 <> &TAbPrc4 or &OldTabPrc5 <> &TAbPrc5 or &OldTabPrc6 <> &TAbPrc6 or &OldTabPrc7 <> &TAbPrc7 or &OldTabPrc8 <> &TAbPrc8 or &OldTabPrc9 <> &TAbPrc9)		
								GravaProdutoNaTabelaNovo.Call(&wwpContext.EmpCod, &ProdutosPreco.tabC, &TabALtCod, &ProCod, 1, 'ADD', &TabProDtaIni, &TabProDtaFin, &TAbPrc1, &TAbPrc2, &TAbPrc3, &TAbPrc4, &TAbPrc5,&TAbPrc6,&TAbPrc7,&TAbPrc8,&TAbPrc9, &wwpContext.UserName, &Perc1, &Perc2,&Perc3,&Perc4,&Perc5,&Perc6,&Perc7,&Perc8,&Perc9)
							EndIf
						EndFor
					EndIf

					If &OqueFazer = 'INS'
						//GRAVA ESTOQUE INICIAL
						&EstQtd = val(&sdtProduto.EstQtd)
						if &EstQtd > 0
							GravaBalancoAcertoEstoque.Call(&wwpContext.EmpCod, &wwpContext.FilCod, &ProCod, 1, &EstQtd)
						EndIf

						////if &sdtConfSistema_CadastroProduto.TCon130_MostrarTabelaPreco = 'N' //JDF VALIDAR NO APP ESSA QUESTAO
						////	adicionarPrecoProduto.Call('Produtos', &wwpContext.EmpCod, &Context.FilCod, &ProCod, 0, &Context.UserName, false)
						////Endif

						&sdtRetornowbs.Obs = format('Produto: %1 Inserido com sucesso!', &outProRef.Trim())
					Else
						&sdtRetornowbs.Obs = format('Produto: %1 Atualizado com sucesso!', &outProRef.Trim())
					EndiF

					&sdtRetornowbs.Sts = 'J200'				
			EndCase
	EndCAse
EndSub


Sub 'Exception_handler'
	&sdtRetornowbs.Sts = 'E999'
	GravaLogDevNew(&wwpContext.EmpCod,&LogGUID,&Pgmname,'Exception_handler: &GXexceptionType',&GXexceptionType)
	GravaLogDevNew(&wwpContext.EmpCod,&LogGUID,&Pgmname,'Exception_handler: &GXExceptionDetails',&GXExceptionDetails)
	GravaLogDevNew(&wwpContext.EmpCod,&LogGUID,&Pgmname,'Exception_handler: &GXExceptionStack',&GXExceptionStack)
	GravaLogDevNew(&wwpContext.EmpCod,&LogGUID,&Pgmname,'subError_handler',&sdtProduto.ToJson())
Endsub

Sub 'Error_handler'
	&sdtRetornowbs.Sts = 'E998'
	GravaLogDevNew(&wwpContext.EmpCod,&LogGUID,&Pgmname,'Error_handler: &Err',&Err.ToFormattedString())
	GravaLogDevNew(&wwpContext.EmpCod,&LogGUID,&Pgmname,'Error_handler: &gxDBErr',&gxDBErr.ToFormattedString())
	GravaLogDevNew(&wwpContext.EmpCod,&LogGUID,&Pgmname,'Error_handler: &GxDbSqlState',&GxDbSqlState)
	GravaLogDevNew(&wwpContext.EmpCod,&LogGUID,&Pgmname,'Error_handler: &gxDBTxt',&gxDBTxt)
	GravaLogDevNew(&wwpContext.EmpCod,&LogGUID,&Pgmname,'Error_handler: &gxOper',&gxOper)
	GravaLogDevNew(&wwpContext.EmpCod,&LogGUID,&Pgmname,'Error_handler: &gxErrTbl',&gxErrTbl)
	GravaLogDevNew(&wwpContext.EmpCod,&LogGUID,&Pgmname,'Error_handler: &gxErrOpt',&gxErrOpt.ToFormattedString())
Endsub

parm(in:&DevRandon, in:&OqueFazer, in:&sdtProduto, out:&sdtRetornowbs);


Exception_handler('Exception_handler');

Error_handler('Error_handler');
